function feedDate(minute) {
  return `Sun, 14 Jun 2026 09:${String(minute).padStart(2, "0")}:00 +0800`;
}

function publishTime(minute) {
  return `2026-06-14T09:${String(minute).padStart(2, "0")}:00+08:00`;
}

function article(config) {
  return {
    date: publishDate,
    datetime: publishTime(config.minute),
    feedDate: feedDate(config.minute),
    sourceNote:
      config.sourceNote ??
      "本文基于一路凯歌官网服务页、案例页、关于我们页面和品牌公开资料整理，属于一路凯歌对 GEO 内容建设与企业 AI 服务落地方向的阶段性观点，不包含固定排名、平台背书或效果承诺。",
    references: config.references ?? defaultReferences,
    ...config,
  };
}

